class NewPostBar{constructor(){this.container=null,this.titleInput=null,this.micButton=null,this.init()}init(){this.container=document.getElementById("newPostBarContainer"),this.container?(this.render(),this.bindEvents(),console.log("[NewPostBar] Initialized")):console.warn("[NewPostBar] Container #newPostBarContainer not found")}render(){this.container.innerHTML=`\n            \x3c!-- New Post Bar (Facebook-style) --\x3e\n            <div class="bg-gradient-to-br from-gray-800/80 via-gray-800/60 to-gray-900/80 backdrop-blur-md rounded-2xl p-6 border border-gray-700/50 shadow-xl hover:shadow-purple-500/10 transition-all duration-300 mb-6">\n\n                \x3c!-- User Avatar + Input Row --\x3e\n                <div class="flex items-center gap-4 mb-4">\n                    \x3c!-- User Avatar --\x3e\n                    <img src="${window.Need2Talk?.user?.avatar_url||"/assets/img/default-avatar.png"}"\n                         alt="${window.Need2Talk?.user?.nickname||"You"}"\n                         class="w-12 h-12 rounded-full border-2 border-purple-500/50 shadow-lg"\n                         loading="lazy">\n\n                    \x3c!-- Title Input (Placeholder) --\x3e\n                    <div class="flex-1 relative">\n                        <input type="text"\n                               id="newPostTitleInput"\n                               placeholder="Dai un titolo al tuo messaggio vocale..."\n                               maxlength="100"\n                               class="w-full bg-gray-700/50 border border-gray-600/50 text-white placeholder-gray-400 rounded-xl px-5 py-3.5 focus:ring-2 focus:ring-purple-500/50 focus:border-purple-500 transition-all duration-200 text-base"\n                               autocomplete="off">\n\n                        \x3c!-- Character Counter --\x3e\n                        <span class="absolute right-3 top-1/2 -translate-y-1/2 text-xs text-gray-500" id="titleCharCounter">0/100</span>\n                    </div>\n\n                    \x3c!-- Mic Button (Purple gradient, opens modal) --\x3e\n                    <button type="button"\n                            id="newPostMicButton"\n                            class="group relative bg-gradient-to-br from-purple-600 to-pink-600 hover:from-purple-500 hover:to-pink-500 text-white rounded-xl px-6 py-3.5 font-semibold shadow-lg hover:shadow-purple-500/50 transition-all duration-300 transform hover:scale-105 active:scale-95 flex items-center gap-2"\n                            title="Registra messaggio vocale">\n\n                        \x3c!-- Microphone Icon --\x3e\n                        <svg class="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2.5">\n                            <path stroke-linecap="round" stroke-linejoin="round" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"></path>\n                        </svg>\n\n                        <span class="hidden sm:inline">Registra</span>\n\n                        \x3c!-- Pulse Ring (subtle animation) --\x3e\n                        <span class="absolute -inset-1 bg-purple-500/30 rounded-xl blur-md opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none"></span>\n                    </button>\n                </div>\n\n                \x3c!-- Helper Text (Emotion Required) --\x3e\n                <div class="flex items-start gap-2 text-sm text-gray-400 bg-gray-700/30 rounded-lg p-3 border border-gray-600/30">\n                    <svg class="w-5 h-5 text-purple-400 flex-shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">\n                        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path>\n                    </svg>\n                    <div>\n                        <span class="font-semibold text-purple-300">Ricorda:</span>\n                        Selezionare un'<strong class="text-white">emozione è obbligatorio</strong> prima di registrare.\n                        <span class="text-gray-500">Aiuta gli altri a connettersi con te.</span>\n                    </div>\n                </div>\n\n            </div>\n        `,this.titleInput=document.getElementById("newPostTitleInput"),this.micButton=document.getElementById("newPostMicButton")}bindEvents(){this.titleInput&&this.micButton&&(this.titleInput.addEventListener("input",()=>{const t=document.getElementById("titleCharCounter");if(t){const e=this.titleInput.value.length;t.textContent=`${e}/100`,e>=90?t.classList.add("text-yellow-400","font-semibold"):t.classList.remove("text-yellow-400","font-semibold")}}),this.micButton.addEventListener("click",()=>{console.log("[NewPostBar] Mic button clicked");const t=this.titleInput.value.trim();if(window.floatingRecorder&&"function"==typeof window.floatingRecorder.openModal)t?(window.floatingRecorder.openModal(),setTimeout(()=>{const e=document.querySelector("#floating-recorder-modal #post-title");e&&(e.value=t,console.log("[NewPostBar] Pre-filled title in modal:",t))},100)):window.floatingRecorder.openModal();else{console.error("[NewPostBar] FloatingRecorder instance not found");const t=document.getElementById("floating-recorder-button");t&&(t.scrollIntoView({behavior:"smooth",block:"center"}),t.style.animation="pulse 1s ease-in-out 3")}}),this.container.addEventListener("click",t=>{t.target===this.micButton||this.micButton.contains(t.target)||this.titleInput.focus()}))}getTitle(){return this.titleInput?this.titleInput.value.trim():""}clearTitle(){if(this.titleInput){this.titleInput.value="";const t=document.getElementById("titleCharCounter");t&&(t.textContent="0/100")}}}"loading"===document.readyState?document.addEventListener("DOMContentLoaded",()=>{window.newPostBar=new NewPostBar}):window.newPostBar=new NewPostBar;